```typescript
class UniqueIDGenerator {
  private lastID: number = 0;

  generateID(): string {
    const timestamp = Date.now();
    const randomPart = Math.floor(Math.random() * 10000);
    const id = `${timestamp}-${randomPart}`;

    // Ensure uniqueness by checking against the last generated ID
    while (id === this.lastID) {
      randomPart = Math.floor(Math.random() * 10000);
      id = `${timestamp}-${randomPart}`;
    }

    this.lastID = id;
    return id;
  }
}

// Example usage:
const generator = new UniqueIDGenerator();
console.log(generator.generateID()); // Example output: "1684957234-3456"
console.log(generator.generateID()); // Example output: "1684957234-7890"
```

This implementation ensures that each ID is unique by using the current timestamp as the base and appending a random part. The `while` loop ensures that if the generated ID is the same as the last one, it will regenerate until a unique ID is produced.

